\displaystyle{\begin{aligned}
   {\frac{\frac{5y}{y^{2}-4}-6}{\frac{3}{y+2}-\frac{5}{y-2}}}
      \amp = {\frac{\frac{5y}{\left(y+2\right)\mathopen{}\left(y-2\right)}-6}{\frac{3}{y+2}-\frac{5}{y-2}}} \\
      \amp = {\frac{\frac{5y}{\left(y+2\right)\mathopen{}\left(y-2\right)}-6}{\frac{3}{y+2}-\frac{5}{y-2}}} \cdot \frac{{\left(y+2\right)\mathopen{}\left(y-2\right)}}{{\left(y+2\right)\mathopen{}\left(y-2\right)}} \\
      \amp = {\frac{\frac{5y}{\left(y+2\right)\mathopen{}\left(y-2\right)}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)-6\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)}{\frac{3}{y+2}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)-\frac{5}{y-2}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)}} \\
      \amp = {\frac{5y-6\mathopen{}\left(y^{2}-4\right)}{3\mathopen{}\left(y-2\right)-5\mathopen{}\left(y+2\right)}}, y \ne 2 \text{ and } y \ne -2 \\
      \amp = {\frac{5y-6y^{2}+24}{3y-6-5y-10}}, y \ne 2 \text{ and } y \ne -2 \\
      \amp = {\frac{-6y^{2}+5y+24}{2\mathopen{}\left(-y-8\right)}, y\ne -2\hbox{ and }y\ne 2}
